import { useMemo, useState } from "react";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";
import { formatCurrencyValue, useCurrencyVersion } from "@/lib/currency";

const FAQS = [
  { q: "What is a mutual fund?", a: "A mutual fund pools money from many investors to buy a portfolio of stocks, bonds, or other assets managed according to a strategy." },
  { q: "What is SIP investing?", a: "SIP means systematic investment plan. It is a method of investing a fixed amount regularly, often monthly." },
  { q: "What is CAGR?", a: "CAGR is compound annual growth rate. It shows the annualized rate that turns the invested amount into the ending value over time." },
  { q: "What is the difference between active and passive mutual funds?", a: "Active funds try to outperform a benchmark through manager decisions. Passive funds track an index at usually lower cost." },
  { q: "What fees do mutual funds charge?", a: "Mutual funds may charge expense ratios, sales loads, redemption fees, or account fees depending on the fund." },
];

const money = (v: number, d = 0) => formatCurrencyValue(Number.isFinite(v) ? v : 0, { maximumFractionDigits: d });
const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";

function futureValue(initial: number, monthly: number, annualReturn: number, years: number) {
  const r = annualReturn / 100 / 12;
  const n = years * 12;
  if (r === 0) return initial + monthly * n;
  return initial * Math.pow(1 + r, n) + monthly * ((Math.pow(1 + r, n) - 1) / r);
}

export default function MutualFundCalculator() {
  useCurrencyVersion();
  const [initial, setInitial] = useState(5000);
  const [monthly, setMonthly] = useState(500);
  const [annualReturn, setAnnualReturn] = useState(10);
  const [years, setYears] = useState(20);
  const result = useMemo(() => {
    const finalCorpus = futureValue(initial, monthly, annualReturn, years);
    const invested = initial + monthly * years * 12;
    const returns = finalCorpus - invested;
    const cagr = (Math.pow(finalCorpus / Math.max(1, invested), 1 / years) - 1) * 100;
    const rows = Array.from({ length: Math.min(years, 60) }, (_, i) => {
      const year = i + 1;
      const value = futureValue(initial, monthly, annualReturn, year);
      const investedYear = initial + monthly * year * 12;
      return { year, invested: investedYear, value, returns: value - investedYear };
    });
    return { finalCorpus, invested, returns, cagr, rows };
  }, [initial, monthly, annualReturn, years]);
  const comparison = [6, 8, 10, 12, 15].map((r) => ({ rate: r, y5: futureValue(0, 500, r, 5), y10: futureValue(0, 500, r, 10), y20: futureValue(0, 500, r, 20), y30: futureValue(0, 500, r, 30) }));

  return (
    <>
      <SEOHead title="Free Mutual Fund Calculator Online - Calculate SIP Returns and Fund Growth Instantly | CalcHive" description="Free online mutual fund calculator. Calculate SIP returns, total corpus and CAGR for any initial investment, monthly contribution and return rate instantly. 100% free, no signup required." canonical="/mutual-fund-calculator" keywords="free mutual fund calculator, SIP calculator free online, mutual fund return calculator free, calculate SIP returns free, investment fund calculator free online" category="Financial Calculators" breadcrumbName="Free Mutual Fund Calculator Online" schemaType="WebApplication" schemaApplicationCategory="CalculatorApplication" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-sky-600 dark:text-sky-400 bg-sky-50 dark:bg-sky-950/50 px-3 py-1 rounded-full mb-4 inline-block">Financial</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Mutual Fund Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Calculate SIP returns, fund growth, total invested amount, and CAGR.</p></div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8">
            <div><label className="text-sm font-semibold text-foreground block mb-2">Initial investment</label><input type="number" value={initial} onChange={(e) => setInitial(Number(e.target.value))} className={inputClass} /></div>
            <div><label className="text-sm font-semibold text-foreground block mb-2">Monthly SIP contribution</label><input type="number" value={monthly} onChange={(e) => setMonthly(Number(e.target.value))} className={inputClass} /></div>
            <div><label className="text-sm font-semibold text-foreground block mb-2">Expected annual return (%)</label><input type="number" value={annualReturn} onChange={(e) => setAnnualReturn(Number(e.target.value))} className={inputClass} /></div>
            <div><label className="text-sm font-semibold text-foreground block mb-2">Investment period (years)</label><input type="number" value={years} onChange={(e) => setYears(Number(e.target.value))} className={inputClass} /></div>
          </div>
          <div className="bg-gradient-to-br from-sky-500 to-sky-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Final Corpus</p><p className="text-5xl sm:text-6xl font-black text-white">{money(result.finalCorpus)}</p></div>
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-3 mt-4"><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Total invested</p><p className="text-lg font-extrabold text-foreground">{money(result.invested)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Total returns</p><p className="text-lg font-extrabold text-foreground">{money(result.returns)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">CAGR</p><p className="text-lg font-extrabold text-foreground">{result.cagr.toFixed(2)}%</p></div></div>
        </section>
        <ShareButton />
        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate Mutual Fund SIP Returns for Free</h2><p className="text-muted-foreground leading-relaxed">This SIP calculator compounds the initial investment and adds each monthly contribution to estimate fund growth over time.</p>
          <h2 className="text-2xl font-bold text-foreground">How Regular Monthly Investments Grow Your Mutual Fund</h2>
          <div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">Mutual Fund Growth at Different Returns - $500/month SIP</caption><thead className="bg-muted/60"><tr>{["Annual Return", "5 Years", "10 Years", "20 Years", "30 Years"].map((h) => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{comparison.map((row) => <tr key={row.rate}><td className="py-2.5 px-3 font-semibold">{row.rate}%</td><td className="py-2.5 px-3">{money(row.y5)}</td><td className="py-2.5 px-3">{money(row.y10)}</td><td className="py-2.5 px-3">{money(row.y20)}</td><td className="py-2.5 px-3">{money(row.y30)}</td></tr>)}</tbody></table></div>
          <h2 className="text-2xl font-bold text-foreground">Free SIP and Fund Return Calculator for Investors</h2>
          <div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">Year by Year Growth Table</caption><thead className="bg-muted/60"><tr>{["Year", "Invested", "Fund Value", "Returns"].map((h) => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{result.rows.map((row) => <tr key={row.year}><td className="py-2.5 px-3">{row.year}</td><td className="py-2.5 px-3">{money(row.invested)}</td><td className="py-2.5 px-3">{money(row.value)}</td><td className="py-2.5 px-3">{money(row.returns)}</td></tr>)}</tbody></table></div>
        </section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" /><RelatedTools exclude="/mutual-fund-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


